**Blockchain Network Incentives Management Script**

```python
# Block Reward Schedule
class BlockRewardSchedule:
    def __init__(self, initial_reward, decrease_rate, max_reward):
        self.initial_reward = initial_reward
        self.decrease_rate = decrease_rate
        self.max_reward = max_reward

    def calculate_reward(self, block_number):
        if block_number < 210000:
            return self.initial_reward
        else:
            return self.max_reward

# Transaction Fee Structure
class TransactionFeeStructure:
    def __init__(self, fixed_fee, percentage_fee):
        self.fixed_fee = fixed_fee
        self.percentage_fee = percentage_fee

    def calculate_fee(self, transaction_amount):
        return self.fixed_fee + (transaction_amount * self.percentage_fee)

# Block Reward Distribution
class BlockRewardDistribution:
    def __init__(self, miner_share, validator_share, network_share):
        self.miner_share = miner_share
        self.validator_share = validator_share
        self.network_share = network_share

    def distribute_reward(self, block_reward):
        return {
            'miner': block_reward * self.miner_share,
            'validator': block_reward * self.validator_share,
            'network': block_reward * self.network_share
        }

# Validator Selection Mechanism
class ValidatorSelectionMechanism:
    def __init__(self, stake_threshold):
        self.stake_threshold = stake_threshold

    def select_validators(self, validators):
        return [validator for validator in validators if validator['stake'] >= self.stake_threshold]

# Consensus Mechanism
class ConsensusMechanism:
    def __init__(self, consensus_type):
        self.consensus_type = consensus_type

    def validate_transactions(self, transactions):
        if self.consensus_type == 'PoS':
            return self.validate_transactions_poS(transactions)
        else:
            return self.validate_transactions_default(transactions)

    def validate_transactions_poS(self, transactions):
        # Proof-of-stake consensus mechanism implementation
        pass

    def validate_transactions_default(self, transactions):
        # Default consensus mechanism implementation
        pass

# Blockchain Network Incentives Management
class BlockchainNetworkIncentivesManagement:
    def __init__(self, block_reward_schedule, transaction_fee_structure, block_reward_distribution, validator_selection_mechanism, consensus_mechanism):
        self.block_reward_schedule = block_reward_schedule
        self.transaction_fee_structure = transaction_fee_structure
        self.block_reward_distribution = block_reward_distribution
        self.validator_selection_mechanism = validator_selection_mechanism
        self.consensus_mechanism = consensus_mechanism

    def manage_incentives(self, block_number, transactions):
        block_reward = self.block_reward_schedule.calculate_reward(block_number)
        transaction_fees = [self.transaction_fee_structure.calculate_fee(transaction['amount']) for transaction in transactions]
        block_reward_distribution = self.block_reward_distribution.distribute_reward(block_reward)
        validators = self.validator_selection_mechanism.select_validators([{'stake': 1000}])
        self.consensus_mechanism.validate_transactions(transactions)
        return block_reward_distribution, transaction_fees, validators

# Example usage
block_reward_schedule = BlockRewardSchedule(6.25, 0.5, 0.0625)
transaction_fee_structure = TransactionFeeStructure(0.0001, 0.1)
block_reward_distribution = BlockRewardDistribution(0.5, 0.25, 0.25)
validator_selection_mechanism = ValidatorSelectionMechanism(1000)
consensus_mechanism = ConsensusMechanism('PoS')
incentives_management = BlockchainNetworkIncentivesManagement(block_reward_schedule, transaction_fee_structure, block_reward_distribution, validator_selection_mechanism, consensus_mechanism)

block_number = 100000
transactions = [{'amount': 10}, {'amount': 20}]
block_reward_distribution, transaction_fees, validators = incentives_management.manage_incentives(block_number, transactions)
print(block_reward_distribution)
print(transaction_fees)
print(validators)
```

This script defines the classes and methods for managing the incentives in a blockchain network. The `BlockchainNetworkIncentivesManagement` class takes in the block reward schedule, transaction fee structure, block reward distribution, validator selection mechanism, and consensus mechanism as parameters. The `manage_incentives` method calculates the block reward, transaction fees, and validator selection based on the input parameters. The example usage at the end demonstrates how to create an instance of the `BlockchainNetworkIncentivesManagement` class and call the `manage_incentives` method.
